@namespace sv_ef597fcf86c74169a74fecbcb12256f6.Components.Pages.Board

<div class="card mb-2 task-card">
    <div class="card-body p-2">
        <h6 class="card-title mb-1">@Task.Title</h6>
        <p class="card-text text-muted small mb-1">@Task.Assignee</p>
        <div class="d-flex justify-content-between align-items-center mb-1">
            <span class="badge @PriorityClass">@Task.Priority</span>
            <small class="text-muted">@Task.DueDate.ToString("MMM dd")</small>
        </div>
        <div class="d-flex justify-content-between">
            @if (ShowMoveLeft)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="OnMoveLeft">← Move Left</button>
            }
            else
            {
                <span></span>
            }
            @if (ShowMoveRight)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="OnMoveRight">Move Right →</button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public EventCallback OnMoveLeft { get; set; }
    [Parameter] public EventCallback OnMoveRight { get; set; }

    private string PriorityClass => Task.Priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };
}

@namespace sv_ef597fcf86c74169a74fecbcb12256f6.Components.Pages.Board

<div class="card mt-2 border-primary">
    <div class="card-body p-2">
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Title"
                   @bind="title" />
        </div>
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Assignee"
                   @bind="assignee" />
        </div>
        <div class="mb-2">
            <select class="form-select form-select-sm" @bind="priority">
                <option value="High">High</option>
                <option value="Medium">Medium</option>
                <option value="Low">Low</option>
            </select>
        </div>
        <div class="mb-2">
            <input type="date" class="form-control form-control-sm" @bind="dueDate" />
        </div>
        <div class="d-flex gap-2">
            <button class="btn btn-primary btn-sm" @onclick="HandleSave" disabled="@isSaving">
                @(isSaving ? "Saving..." : "Save")
            </button>
            <button class="btn btn-secondary btn-sm" @onclick="HandleCancel" disabled="@isSaving">
                Cancel
            </button>
        </div>
    </div>
</div>

@code {
    [Parameter] public string Status { get; set; } = "To Do";
    [Parameter] public EventCallback<NewTaskModel> OnSave { get; set; }
    [Parameter] public EventCallback OnCancel { get; set; }

    private string title = string.Empty;
    private string assignee = string.Empty;
    private string priority = "Medium";
    private DateTime dueDate = DateTime.Today.AddDays(7);
    private bool isSaving;

    private async Task HandleSave()
    {
        if (string.IsNullOrWhiteSpace(title)) return;

        isSaving = true;
        await OnSave.InvokeAsync(new NewTaskModel(title, assignee, priority, dueDate));
        isSaving = false;

        title = string.Empty;
        assignee = string.Empty;
        priority = "Medium";
        dueDate = DateTime.Today.AddDays(7);
    }

    private async Task HandleCancel()
    {
        await OnCancel.InvokeAsync();
    }

    public record NewTaskModel(string Title, string Assignee, string Priority, DateTime DueDate);
}

@namespace sv_ef597fcf86c74169a74fecbcb12256f6.Components.Pages.Board

<div class="col kanban-column d-flex flex-column">
    <div class="card h-100">
        <div class="card-header d-flex justify-content-between align-items-center">
            <h5 class="mb-0">@ColumnName</h5>
            <span class="badge bg-secondary">@Tasks.Count</span>
        </div>
        <div class="card-body overflow-auto p-2">
            @foreach (var task in Tasks)
            {
                <TaskCard Task="task"
                          ShowMoveLeft="ShowMoveLeft"
                          ShowMoveRight="ShowMoveRight"
                          OnMoveLeft="() => HandleMoveLeft(task)"
                          OnMoveRight="() => HandleMoveRight(task)" />
            }

            @if (showAddForm)
            {
                <AddTaskForm Status="@Status"
                             OnSave="HandleNewTask"
                             OnCancel="() => showAddForm = false" />
            }
        </div>
        <div class="card-footer">
            <button class="btn btn-outline-primary btn-sm w-100" @onclick="() => showAddForm = true"
                    disabled="@showAddForm">
                + Add Task
            </button>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string ColumnName { get; set; } = string.Empty;
    [Parameter, EditorRequired] public string Status { get; set; } = string.Empty;
    [Parameter] public List<TaskItem> Tasks { get; set; } = new();
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public EventCallback<TaskItem> OnMoveLeft { get; set; }
    [Parameter] public EventCallback<TaskItem> OnMoveRight { get; set; }
    [Parameter] public EventCallback<AddTaskForm.NewTaskModel> OnAddTask { get; set; }

    private bool showAddForm;

    private async Task HandleMoveLeft(TaskItem task) => await OnMoveLeft.InvokeAsync(task);
    private async Task HandleMoveRight(TaskItem task) => await OnMoveRight.InvokeAsync(task);

    private async Task HandleNewTask(AddTaskForm.NewTaskModel model)
    {
        await OnAddTask.InvokeAsync(model);
        showAddForm = false;
    }
}

@namespace sv_ef597fcf86c74169a74fecbcb12256f6.Components.Pages.Board

<div class="mb-3">
    <input type="text" class="form-control" placeholder="Search tasks by title..."
           @bind="SearchText" @bind:event="oninput" @bind:after="NotifyChanged" />
</div>

@code {
    [Parameter] public string SearchText { get; set; } = string.Empty;
    [Parameter] public EventCallback<string> SearchTextChanged { get; set; }

    private async Task NotifyChanged() => await SearchTextChanged.InvokeAsync(SearchText);
}

@page "/board"
@namespace sv_ef597fcf86c74169a74fecbcb12256f6.Components.Pages.Board
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (isLoading)
{
    <div class="text-center py-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
        <p class="mt-2 text-muted">Loading tasks...</p>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-link" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStatsBar Tasks="tasks" />
    <BoardSearchBar @bind-SearchText="searchText" />

    <div class="row g-3 kanban-board">
        @foreach (var col in columns)
        {
            var colIndex = Array.IndexOf(columns, col);
            <KanbanColumn ColumnName="@col"
                          Status="@col"
                          Tasks="GetFilteredTasksForStatus(col)"
                          ShowMoveLeft="colIndex > 0"
                          ShowMoveRight="colIndex < columns.Length - 1"
                          OnMoveLeft="task => MoveTask(task, columns[colIndex - 1])"
                          OnMoveRight="task => MoveTask(task, columns[colIndex + 1])"
                          OnAddTask="model => AddTask(model, col)" />
        }
    </div>
}

@code {
    private static readonly string[] columns = { "To Do", "In Progress", "Done" };

    private List<TaskItem> tasks = new();
    private string searchText = string.Empty;
    private bool isLoading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        try
        {
            isLoading = true;
            errorMessage = null;
            tasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private List<TaskItem> GetFilteredTasksForStatus(string status)
    {
        var filtered = tasks.Where(t => t.Status == status);
        if (!string.IsNullOrWhiteSpace(searchText))
        {
            filtered = filtered.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase));
        }
        return filtered.ToList();
    }

    private async Task MoveTask(TaskItem task, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
            var index = tasks.FindIndex(t => t.Id == task.Id);
            if (index >= 0)
            {
                tasks[index] = task with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }

    private async Task AddTask(AddTaskForm.NewTaskModel model, string status)
    {
        try
        {
            var newTask = await TaskService.CreateTaskAsync(model.Title, model.Assignee, model.Priority, model.DueDate);
            // The service creates with a default status; ensure it matches the column
            if (newTask.Status != status)
            {
                await TaskService.UpdateTaskStatusAsync(newTask.Id, status);
                newTask = newTask with { Status = status };
            }
            tasks.Add(newTask);
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }
}

