@namespace sv_ef597fcf86c74169a74fecbcb12256f6.Components.Pages.Board

<div class="mb-3">
    <input type="text" class="form-control" placeholder="Search tasks by title..."
           @bind="SearchText" @bind:event="oninput" @bind:after="NotifyChanged" />
</div>

@code {
    [Parameter] public string SearchText { get; set; } = string.Empty;
    [Parameter] public EventCallback<string> SearchTextChanged { get; set; }

    private async Task NotifyChanged() => await SearchTextChanged.InvokeAsync(SearchText);
}

@page "/board"
@namespace sv_ef597fcf86c74169a74fecbcb12256f6.Components.Pages.Board
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (isLoading)
{
    <div class="text-center py-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
        <p class="mt-2 text-muted">Loading tasks...</p>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @errorMessage
        <button class="btn btn-link" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStatsBar Tasks="tasks" />
    <BoardSearchBar @bind-SearchText="searchText" />

    <div class="row g-3 kanban-board">
        @foreach (var col in columns)
        {
            var colIndex = Array.IndexOf(columns, col);
            <KanbanColumn ColumnName="@col"
                          Status="@col"
                          Tasks="GetFilteredTasksForStatus(col)"
                          ShowMoveLeft="colIndex > 0"
                          ShowMoveRight="colIndex < columns.Length - 1"
                          OnMoveLeft="task => MoveTask(task, columns[colIndex - 1])"
                          OnMoveRight="task => MoveTask(task, columns[colIndex + 1])"
                          OnAddTask="model => AddTask(model, col)" />
        }
    </div>
}

@code {
    private static readonly string[] columns = { "To Do", "In Progress", "Done" };

    private List<TaskItem> tasks = new();
    private string searchText = string.Empty;
    private bool isLoading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        try
        {
            isLoading = true;
            errorMessage = null;
            tasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private List<TaskItem> GetFilteredTasksForStatus(string status)
    {
        var filtered = tasks.Where(t => t.Status == status);
        if (!string.IsNullOrWhiteSpace(searchText))
        {
            filtered = filtered.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase));
        }
        return filtered.ToList();
    }

    private async Task MoveTask(TaskItem task, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
            var index = tasks.FindIndex(t => t.Id == task.Id);
            if (index >= 0)
            {
                tasks[index] = task with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }

    private async Task AddTask(AddTaskForm.NewTaskModel model, string status)
    {
        try
        {
            var newTask = await TaskService.CreateTaskAsync(model.Title, model.Assignee, model.Priority, model.DueDate);
            // The service creates with a default status; ensure it matches the column
            if (newTask.Status != status)
            {
                await TaskService.UpdateTaskStatusAsync(newTask.Id, status);
                newTask = newTask with { Status = status };
            }
            tasks.Add(newTask);
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
    }
}

